                        {book.format === "audio" ? (
                          <>
                            <Play size={14} />
                            Tinglash
                          </>
                        ) : (
                          <>
                            <BookOpen size={14} />{' O\'qish '}</>
                        )}
                      </button>
                    </div>
                  </motion.div>
                ))}
              </div>)
            )
          ) : (
            // Empty State with animation
            (<motion.div
              initial={{ opacity: 0, scale: 0.9 }}
